int synq_sqlite3_keywordCode(const SyntaqliteDialectConfig* config,
                             const char* z,
                             int n,
                             int* pType) {
  int i, j;
  const char* zKW;
  assert(n >= 2);
  i = ((charMap(z[0]) * 4) ^ (charMap(z[n - 1]) * 3) ^ n * 1) % 127;
  for (i = (int)aKWHash[i]; i > 0; i = aKWNext[i]) {
    if (synq_sqlite_aKWLen[i] != n)
      continue;
    zKW = &synq_sqlite_zKWText[synq_sqlite_aKWOffset[i]];
#ifdef SQLITE_ASCII
    if ((z[0] & ~0x20) != zKW[0])
      continue;
    if ((z[1] & ~0x20) != zKW[1])
      continue;
    j = 2;
    while (j < n && (z[j] & ~0x20) == zKW[j]) {
      j++;
    }
#endif
#ifdef SQLITE_EBCDIC
    if (toupper(z[0]) != zKW[0])
      continue;
    if (toupper(z[1]) != zKW[1])
      continue;
    j = 2;
    while (j < n && toupper(z[j]) == zKW[j]) {
      j++;
    }
#endif
    if (j < n)
      continue;
    testcase(i == 1);   /* REINDEX */
    testcase(i == 2);   /* INDEXED */
    testcase(i == 3);   /* INDEX */
    testcase(i == 4);   /* DESC */
    testcase(i == 5);   /* ESCAPE */
    testcase(i == 6);   /* EACH */
    testcase(i == 7);   /* CHECK */
    testcase(i == 8);   /* KEY */
    testcase(i == 9);   /* BEFORE */
    testcase(i == 10);  /* FOREIGN */
    testcase(i == 11);  /* FOR */
    testcase(i == 12);  /* IGNORE */
    testcase(i == 13);  /* REGEXP */
    testcase(i == 14);  /* EXPLAIN */
    testcase(i == 15);  /* INSTEAD */
    testcase(i == 16);  /* ADD */
    testcase(i == 17);  /* DATABASE */
    testcase(i == 18);  /* AS */
    testcase(i == 19);  /* SELECT */
    testcase(i == 20);  /* TABLE */
    testcase(i == 21);  /* LEFT */
    testcase(i == 22);  /* THEN */
    testcase(i == 23);  /* END */
    testcase(i == 24);  /* DEFERRABLE */
    testcase(i == 25);  /* ELSE */
    testcase(i == 26);  /* EXCLUDE */
    testcase(i == 27);  /* DELETE */
    testcase(i == 28);  /* TEMPORARY */
    testcase(i == 29);  /* TEMP */
    testcase(i == 30);  /* OR */
    testcase(i == 31);  /* ISNULL */
    testcase(i == 32);  /* NULLS */
    testcase(i == 33);  /* SAVEPOINT */
    testcase(i == 34);  /* INTERSECT */
    testcase(i == 35);  /* TIES */
    testcase(i == 36);  /* NOTNULL */
    testcase(i == 37);  /* NOT */
    testcase(i == 38);  /* NO */
    testcase(i == 39);  /* NULL */
    testcase(i == 40);  /* LIKE */
    testcase(i == 41);  /* EXCEPT */
    testcase(i == 42);  /* TRANSACTION */
    testcase(i == 43);  /* ACTION */
    testcase(i == 44);  /* ON */
    testcase(i == 45);  /* NATURAL */
    testcase(i == 46);  /* ALTER */
    testcase(i == 47);  /* RAISE */
    testcase(i == 48);  /* EXCLUSIVE */
    testcase(i == 49);  /* EXISTS */
    testcase(i == 50);  /* CONSTRAINT */
    testcase(i == 51);  /* INTO */
    testcase(i == 52);  /* OFFSET */
    testcase(i == 53);  /* OF */
    testcase(i == 54);  /* SET */
    testcase(i == 55);  /* TRIGGER */
    testcase(i == 56);  /* RANGE */
    testcase(i == 57);  /* GENERATED */
    testcase(i == 58);  /* DETACH */
    testcase(i == 59);  /* HAVING */
    testcase(i == 60);  /* GLOB */
    testcase(i == 61);  /* BEGIN */
    testcase(i == 62);  /* INNER */
    testcase(i == 63);  /* REFERENCES */
    testcase(i == 64);  /* UNIQUE */
    testcase(i == 65);  /* QUERY */
    testcase(i == 66);  /* WITHOUT */
    testcase(i == 67);  /* WITH */
    testcase(i == 68);  /* OUTER */
    testcase(i == 69);  /* RELEASE */
    testcase(i == 70);  /* ATTACH */
    testcase(i == 71);  /* BETWEEN */
    testcase(i == 72);  /* NOTHING */
    testcase(i == 73);  /* GROUPS */
    testcase(i == 74);  /* GROUP */
    testcase(i == 75);  /* CASCADE */
    testcase(i == 76);  /* ASC */
    testcase(i == 77);  /* DEFAULT */
    testcase(i == 78);  /* CASE */
    testcase(i == 79);  /* COLLATE */
    testcase(i == 80);  /* CREATE */
    testcase(i == 81);  /* CURRENT_DATE */
    testcase(i == 82);  /* IMMEDIATE */
    testcase(i == 83);  /* JOIN */
    testcase(i == 84);  /* INSERT */
    testcase(i == 85);  /* MATCH */
    testcase(i == 86);  /* PLAN */
    testcase(i == 87);  /* ANALYZE */
    testcase(i == 88);  /* PRAGMA */
    testcase(i == 89);  /* MATERIALIZED */
    testcase(i == 90);  /* DEFERRED */
    testcase(i == 91);  /* DISTINCT */
    testcase(i == 92);  /* IS */
    testcase(i == 93);  /* UPDATE */
    testcase(i == 94);  /* VALUES */
    testcase(i == 95);  /* VIRTUAL */
    testcase(i == 96);  /* ALWAYS */
    testcase(i == 97);  /* WHEN */
    testcase(i == 98);  /* WHERE */
    testcase(i == 99);  /* RECURSIVE */
    testcase(i == 100); /* WITHIN */
    testcase(i == 101); /* INITIALLY */
    testcase(i == 102); /* ALL */
    testcase(i == 103); /* ABORT */
    testcase(i == 104); /* AFTER */
    testcase(i == 105); /* RENAME */
    testcase(i == 106); /* AND */
    testcase(i == 107); /* DROP */
    testcase(i == 108); /* PARTITION */
    testcase(i == 109); /* AUTOINCREMENT */
    testcase(i == 110); /* TO */
    testcase(i == 111); /* IN */
    testcase(i == 112); /* CAST */
    testcase(i == 113); /* COLUMN */
    testcase(i == 114); /* COMMIT */
    testcase(i == 115); /* CONFLICT */
    testcase(i == 116); /* CROSS */
    testcase(i == 117); /* CURRENT_TIMESTAMP */
    testcase(i == 118); /* CURRENT_TIME */
    testcase(i == 119); /* CURRENT */
    testcase(i == 120); /* PRECEDING */
    testcase(i == 121); /* FAIL */
    testcase(i == 122); /* LAST */
    testcase(i == 123); /* FILTER */
    testcase(i == 124); /* REPLACE */
    testcase(i == 125); /* FIRST */
    testcase(i == 126); /* FOLLOWING */
    testcase(i == 127); /* FROM */
    testcase(i == 128); /* FULL */
    testcase(i == 129); /* LIMIT */
    testcase(i == 130); /* IF */
    testcase(i == 131); /* ORDER */
    testcase(i == 132); /* RESTRICT */
    testcase(i == 133); /* OTHERS */
    testcase(i == 134); /* OVER */
    testcase(i == 135); /* RETURNING */
    testcase(i == 136); /* RIGHT */
    testcase(i == 137); /* ROLLBACK */
    testcase(i == 138); /* ROWS */
    testcase(i == 139); /* ROW */
    testcase(i == 140); /* UNBOUNDED */
    testcase(i == 141); /* UNION */
    testcase(i == 142); /* USING */
    testcase(i == 143); /* VACUUM */
    testcase(i == 144); /* VIEW */
    testcase(i == 145); /* WINDOW */
    testcase(i == 146); /* DO */
    testcase(i == 147); /* BY */
    testcase(i == 148); /* PRIMARY */
    /* Version check: skip keywords newer than target version. */
    if (synq_sqlite_aKWSince[i] != 0 &&
        SYNQ_VER_LT(config, synq_sqlite_aKWSince[i])) {
      break;
    }
    /* CFlag check with polarity. */
    if (synq_sqlite_aKWCFlag[i] >= 0) {
      int flag_set = SYNQ_HAS_CFLAG(config, synq_sqlite_aKWCFlag[i]);
      int is_enable = synq_sqlite_aKWCFlagPolarity[i];
      if (flag_set != is_enable) {
        break;
      }
    }
    *pType = synq_sqlite_aKWCode[i];
    break;
  }
  return n;
}

const unsigned int synq_sqlite_nKeyword =
    sizeof(synq_sqlite_aKWCode) / sizeof(synq_sqlite_aKWCode[0]);
